function fictionalEmail(name: string): string {
  return (
    name
      .toLowerCase()
      .replace(/^dr\.\s*/, "")
      .replace(/[^a-z\s]/g, "")
      .trim()
      .replace(/\s+/g, ".") + "@mesavistarx.com"
  );
}

